class Solution {
    public int[] countBits(int n) {
        int[] result = new int[n + 1];
        for (int i = 1; i <= n; i++) {
            result[i] = i;
        }
        for (int i = 2; i <= n; i *= 2) {
            for (int j = i; j <= n; j += i) {
                result[j] -= result[j / i];
            }
        }
        return result;
    }
}
```

